const listMap = {
  "LIST_ID_DONE": "Done",
  "LIST_ID_BACKLOG": "Backlog",
  "LIST_ID_IN_PROGRESS": "In Progress",
  "LIST_ID_BLOCKED": "Blocked / Risk Watch"
};

return items.map(item => {
  const card = item.json;

  return {
    json: {
      taskName: card.name || "",
      description: card.desc || "No description provided",
      dueDate: card.due || null,
      status: listMap[card.idList] || "Unknown",
      completed: card.dueComplete || false,
      label: card.labels && card.labels.length > 0 ? card.labels[0].name : "No Label",
      shortUrl: card.shortUrl || ""
    }
  };
});

const grouped = {
  Done: [],
  "In Progress": [],
  "Blocked / Risk Watch": [],
  Backlog: []
};

for (const item of items) {
  const task = item.json;
  if (grouped[task.status]) {
    grouped[task.status].push(task);
  }
}

return [
  {
    json: {
      totalTasks: items.length,
      doneCount: grouped["Done"].length,
      inProgressCount: grouped["In Progress"].length,
      blockedCount: grouped["Blocked / Risk Watch"].length,
      backlogCount: grouped["Backlog"].length,
      done: grouped["Done"],
      inProgress: grouped["In Progress"],
      blocked: grouped["Blocked / Risk Watch"],
      backlog: grouped["Backlog"]
    }
  }
];

const raw = $json.output || "";

// Escape HTML special characters first
function escapeHtml(text) {
  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

const lines = raw.split("\n").map(line => line.trim()).filter(line => line !== "");

let html = `
<html>
  <body style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6; color: #222;">
`;

// Track whether we're inside a list
let inList = false;

for (const line of lines) {
  const safeLine = escapeHtml(line);

  // Greeting
  if (safeLine === "Hello Team,") {
    if (inList) {
      html += `</ul>`;
      inList = false;
    }
    html += `<p>Hello Team,</p>`;
    continue;
  }

  // Closing lines
  if (
    safeLine === "Regards," ||
    safeLine === "Mira" ||
    safeLine === "AI Kanban Summariser Agent"
  ) {
    if (inList) {
      html += `</ul>`;
      inList = false;
    }
    html += `<p>${safeLine}</p>`;
    continue;
  }

  // Section headings like "1. Overall Status"
  if (/^\d+\.\s/.test(safeLine)) {
    if (inList) {
      html += `</ul>`;
      inList = false;
    }
    html += `<p style="margin-top: 16px; margin-bottom: 6px;"><strong>${safeLine}</strong></p>`;
    continue;
  }

  // Bullet points
  if (safeLine.startsWith("- ")) {
    if (!inList) {
      html += `<ul style="margin-top: 4px; margin-bottom: 12px; padding-left: 20px;">`;
      inList = true;
    }
    html += `<li>${safeLine.substring(2)}</li>`;
    continue;
  }

  // Normal paragraphs
  if (inList) {
    html += `</ul>`;
    inList = false;
  }

  html += `<p>${safeLine}</p>`;
}

if (inList) {
  html += `</ul>`;
}

html += `
  </body>
</html>
`;

return [
  {
    json: {
      htmlBody: html
    }
  }
];
